<section class="admin-page-head"><div><p class="eyebrow">FULFILLMENT</p><h1>Livrare și AWB</h1><p>Metoda manuală funcționează imediat. Un curier API poate fi activat după introducerea credențialelor.</p></div></section><?php if($notice): ?><div class="admin-alert success"><?= e($notice) ?></div><?php endif; ?><div class="settings-card-grid"><?php foreach($items as $item): $config=json_decode($item['config_json']??'{}',true)?:[]; ?><form class="admin-panel" method="post" action="<?= e(url('/admin/setari/livrare/'.$item['code'])) ?>"><?= csrf_field() ?><div class="panel-head"><div><p class="eyebrow"><?= e($item['environment']) ?></p><h2><?= e($item['name']) ?></h2></div><span class="status-pill <?= $item['is_enabled']?'success':'' ?>"><?= $item['is_enabled']?'Activ':'Inactiv' ?></span></div><div class="admin-form-grid"><label>Mediu<select name="environment"><?php foreach(['manual','sandbox','test','live'] as $environment): ?><option <?= $item['environment']===$environment?'selected':'' ?>><?= e($environment) ?></option><?php endforeach; ?></select></label><label>Cost standard (lei)<input type="number" step="0.01" name="base_price" value="<?= number_format(((int)($config['base_price_minor']??0))/100,2,'.','') ?>"></label><label>Gratuit peste (lei)<input type="number" step="0.01" name="free_threshold" value="<?= number_format(((int)($config['free_threshold_minor']??0))/100,2,'.','') ?>"></label><label>API URL<input name="api_url" value="<?= e($config['api_url']??'') ?>"></label><label>Utilizator API<input name="api_username" autocomplete="off"></label><label>Parolă API<input type="password" name="api_password" autocomplete="new-password" placeholder="<?= $item['credential_id']?'Păstrată criptat':'' ?>"></label></div><label class="check-label"><input type="checkbox" name="is_enabled" value="1" <?= $item['is_enabled']?'checked':'' ?>> Activ</label><label class="check-label"><input type="checkbox" name="is_default" value="1" <?= $item['is_default']?'checked':'' ?>> Implicit</label><button class="admin-button" type="submit">Salvează livrarea</button></form><?php endforeach; ?></div>
